32|        return List.of(
33|            new Module("自定义指令", 80, ""),
34|            new Module("已激活 Skill", 90, ""),
35|            new Module("长期记忆", 100, "")
36|        );
37|    }
38|
39|    /** 按 priority 升序排列，跳过 content 为空的模块，以 "\n\n" 连接 */
40|    public static String assemble(List<Module> modules) {
41|        return modules.stream()
42|            .filter(m -> !m.content().isEmpty())
43|            .sorted(Comparator.comparingInt(Module::priority))
44|            .map(Module::content)
45|            .collect(Collectors.joining("\n\n"));
46|    }
